/// Configuration for allowed cleartext (HTTP) hosts.
/// Only local IoT device IPs on the 192.168.x.x subnet are permitted.
class CleartextPolicy {
  static const String _allowedSubnet = '192.168.';

  /// Returns true only if the host is a local IoT device on 192.168.x.x
  static bool isCleartextAllowed(String host) {
    return host.startsWith(_allowedSubnet);
  }

  /// Validates that a URI complies with our transport security policy.
  /// - HTTPS is always allowed.
  /// - HTTP is only allowed for 192.168.x.x addresses.
  static void enforce(Uri uri) {
    if (uri.scheme == 'http' && !isCleartextAllowed(uri.host)) {
      throw TransportSecurityException(
        'Cleartext HTTP is not allowed for host "${uri.host}". '
        'Only local IoT devices on 192.168.x.x subnet may use HTTP. '
        'Use HTTPS for all other traffic.',
      );
    }
  }
}

