      final response = await request().timeout(effectiveTimeout);
      return response;
    } on SocketException catch (e) {
      throw NetworkException(
        'Failed to connect to ${uri.host}:${uri.port}. '
        'Check network connectivity and device availability.',
        innerException: e,
      );
    } on HandshakeException catch (e) {
      throw NetworkException(
        'TLS handshake failed for ${uri.host}. '
        'The server certificate may be invalid or untrusted.',
        innerException: e,
      );
    } on CertificateException catch (e) {
      throw NetworkException(
        'Certificate verification failed for ${uri.host}. '
        'Ensure the server has a valid TLS certificate.',
        innerException: e,
      );
    } on dart_async.TimeoutException catch (_) {
      throw TimeoutException(
        'Request to ${uri.host}${uri.path} timed out.',
        effectiveTimeout,
      );
    } on http.ClientException catch (e) {
      throw NetworkException(
        'HTTP client error for ${uri.host}: ${e.message}',
        innerException: e,
      );
    }
  }

  void _checkStatusCode(http.Response response) {
    if (response.statusCode >= 200 && response.statusCode < 300) {
      return;
    }

    String message;
    switch (response.statusCode) {
      case 400:
        message = 'Bad request';
        break;
      case 401:
        message = 'Unauthorized - check authentication token';
        break;
      case 403:
        message = 'Forbidden - insufficient permissions';
        break;
      case 404:
        message = 'Resource not found';
        break;
      case 408:
        message = 'Request timeout';
        break;
      case 429:
        message = 'Rate limited - too many requests';
        break;
      case 500:
        message = 'Internal server error';
        break;
      case 502:
        message = 'Bad gateway';
        break;
      case 503:
        message = 'Service unavailable';
        break;
      default:
        message = 'HTTP error ${response.statusCode}';
    }

    throw ApiException(
      statusCode: response.statusCode,
      message: message,
      responseBody: response.body,
      uri: response.request?.url,
    );
  }

  ApiResponse<Map<String, dynamic>> _parseJsonResponse(
    http.Response response,
  ) {
    _checkStatusCode(response);

    try {
      final dynamic decoded = jsonDecode(response.body);
      final Map<String, dynamic> data;

      if (decoded is Map<String, dynamic>) {
        data = decoded;
      } else if (decoded is List) {
        data = {'items': decoded};
      } else {
        data = {'value': decoded};
      }

      return ApiResponse(
        statusCode: response.statusCode,
        data: data,
        headers: response.headers,
      );
    } on FormatException catch (e) {
      throw ApiException(
        statusCode: response.statusCode,
        message: 'Failed to parse JSON response: ${e.message}',
        responseBody: response.body,
        uri: response.request?.url,
      );
    }
  }
